-- ============================================================================
-- V2__seed_test_data.sql  —  DEV/TEST DATA ONLY. Never ship to production.
--
-- Loaded only when the active Flyway locations include classpath:db/seed
-- (dev profile). Production keeps locations=classpath:db/migration.
--
-- Conventions:
--   * 2 tenants with fixed public UUIDs:
--       Tenant 1: 11111111-1111-1111-1111-111111111111  (Wanderlust Holidays, Mumbai, PRO)
--       Tenant 2: 22222222-2222-2222-2222-222222222222  (Namaste Travels, Delhi, STARTER)
--   * Every user password is  Test@123  (bcrypt, strength 10, verified):
--       $2a$10$3ABUp2YJz/5frgIVV.Rw9eHqu2Wakv.fBMOD0qett8vs8wwYGMUBO
--   * Deterministic public_id prefixes per table:
--       users a0…, leads b0…, lead_itinerary c0…, bookings d0…,
--       notifications e0…, reminders f0…
--   * Explicit ids are used so FKs line up; identity sequences are
--     re-synced via setval() at the end of this script.
--   * super_admins is seeded below with same Test@123 password.
--   * city_master: tenant_id = NULL → global (all tenants); non-null → tenant-specific.
-- ============================================================================

-- ============================================================================
-- SUPER ADMIN (seed with same Test@123 password as all other users)
-- ON CONFLICT guard: DataInitializer may have already inserted this row;
-- update password so dev always gets Test@123 regardless of startup order.
-- ============================================================================
INSERT INTO super_admins (id, public_id, created_by, updated_by, created_at, updated_at,
                          name, email, password, enabled) VALUES
    (1, '12a7dd62-90a5-45a3-aae2-1c4b6564bb0a', 'seed', 'seed',
     '2026-01-01 00:00:00', '2026-01-01 00:00:00',
     'Super Admin', 'superadmin@travelcrm.com',
     '$2a$10$3ABUp2YJz/5frgIVV.Rw9eHqu2Wakv.fBMOD0qett8vs8wwYGMUBO', TRUE)
ON CONFLICT (email) DO UPDATE
    SET password   = EXCLUDED.password,
        updated_at = now(),
        updated_by = 'seed';

