-- ============================================================================
-- RE-SYNC IDENTITY SEQUENCES
-- Explicit ids were inserted above; without this, the next runtime INSERT
-- would draw id=1 from the identity sequence and hit a duplicate key error.
-- ============================================================================
SELECT setval(pg_get_serial_sequence('super_admins',       'id'),             (SELECT MAX(id)             FROM super_admins));
SELECT setval(pg_get_serial_sequence('tenants',            'id'),             (SELECT MAX(id)             FROM tenants));
SELECT setval(pg_get_serial_sequence('users',              'id'),             (SELECT MAX(id)             FROM users));
SELECT setval(pg_get_serial_sequence('city_master',        'city_id'),        (SELECT MAX(city_id)        FROM city_master));
SELECT setval(pg_get_serial_sequence('destination_master', 'destination_id'), (SELECT MAX(destination_id) FROM destination_master));
SELECT setval(pg_get_serial_sequence('leads',              'id'),             (SELECT MAX(id)             FROM leads));
SELECT setval(pg_get_serial_sequence('lead_itinerary',     'id'),             (SELECT MAX(id)             FROM lead_itinerary));
SELECT setval(pg_get_serial_sequence('bookings',           'id'),             (SELECT MAX(id)             FROM bookings));
SELECT setval(pg_get_serial_sequence('notifications',      'id'),             (SELECT MAX(id)             FROM notifications));
SELECT setval(pg_get_serial_sequence('reminders',          'id'),             (SELECT MAX(id)             FROM reminders));